import java.io.BufferedWriter;
import java.io.FileWriter;
import java.io.IOException;

import org.apache.commons.text.StringEscapeUtils;

public class XssSecureCode {

    public static void main(String[] args) throws IOException {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Sanitize user input
        String sanitizedUserInput = StringEscapeUtils.escapeHtml4(userInput);

        // Proper handling of user input
        try (BufferedWriter writer = new BufferedWriter(new FileWriter("output.html"))) {
            writer.write("<html>");
            writer.newLine();
            writer.write("<body>");
            writer.newLine();
            writer.write("<h1>Welcome, " + sanitizedUserInput + "</h1>"); // Sanitized user input is included in the HTML response
            writer.newLine();
            writer.write("</body>");
            writer.newLine();
            writer.write("</html>");
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
